sql:
SELECT *
FROM project_managers
WHERE project_manager_id NOT IN (
  SELECT reviewer_id
  FROM reviewers
);

external_knowledge:
- 'seasoned navigators' refers to the experienced reviewers;
- 'guiding the fleet through stormy seas' refers to the process of reviewing solutions, where the reviewers ensure the quality of solutions;
- 'navigation success rates' corresponds to the 'acceptance_rate', indicating the rate at which solutions proposed are accepted by the reviewers;
- 'precision of their maritime charts' relates to the 'code_quality_score', reflecting the quality of the reviewers' evaluations or the solutions they have reviewed.

- "vibrant feedback" refers to reviews that include comments; 
- "latest round" implies limiting to the most recent entries; 
- "within the last month" indicates that the commit time must be within the last 30 days.

sql:
SELECT DISTINCT solution_id
FROM solutions
WHERE submitter_id IN (
  SELECT DISTINCT reviewer_id 
  FROM reviews
);

SELECT review_count, average_time, acceptance_rate, average_rating 
FROM reviewer_performance 
WHERE reviewer_id = 0;

SELECT review_rating
FROM reviews
WHERE code_quality_score = (
  SELECT MAX(code_quality_score)
  FROM reviews
);
